import java.lang.annotation.*;
import java.lang.reflect.*;
import java.util.*;

@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
@interface ApiOperation {
    String summary();
    String description() default "";
    int responseCode() default 200;
    String responseDescription() default "Success";
}

@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
@interface ApiTag { String value(); }

public class UserApi {
    @ApiTag("users")
    @ApiOperation(summary = "Get all users", description = "Returns a list of all registered users")
    public void getUsers() {}

    @ApiTag("users")
    @ApiOperation(summary = "Create user", description = "Creates a new user account", responseCode = 201, responseDescription = "User created")
    public void createUser() {}

    @ApiTag("users")
    @ApiOperation(summary = "Delete user", description = "Deletes a user by ID", responseCode = 204, responseDescription = "No Content")
    public void deleteUser() {}
}

