        System.out.println("  title: " + apiClass.getSimpleName() + " Documentation");
        System.out.println("  version: 1.0.0");
        System.out.println("paths:");

        // TODO: Iterate methods with @ApiOperation annotation
        // Print each method as a path entry with summary, description, response code
    }
}

public class Main {
    public static void main(String[] args) throws Exception {
        new OpenApiGenerator().generateSpec(UserApi.class);
    }
}

import java.util.*;

public class ApiRequest {
    private String url;
    private Map<String, String> headers;
    private Map<String, String> queryParams;

    public ApiRequest(String url, Map<String, String> headers, Map<String, String> queryParams) {
        this.url = url; this.headers = headers; this.queryParams = queryParams;
    }

    public String getUrl() { return url; }
    public Map<String, String> getHeaders() { return headers; }
    public Map<String, String> getQueryParams() { return queryParams; }
}

public class ApiVersionResolver {

    public String resolveUrlVersion(ApiRequest request) {
        // TODO: Extract version from URL pattern /api/v{N}/...
        // Return "v1", "v2", etc. or "unknown"
        return "unknown";
    }

    public String resolveHeaderVersion(ApiRequest request) {
        // TODO: Extract version from Accept header: 'application/vnd.api.v2+json'
        return "unknown";
    }

    public String resolveQueryParamVersion(ApiRequest request) {
        // TODO: Get 'version' query parameter, prefix with 'v'
        return "unknown";
    }
}

public class VersionedUserController {
    public String getUser(String version) {
        return switch (version) {
            case "v1" -> "{\"id\": 1, \"name\": \"Alice\"}";
            case "v2" -> "{\"id\": 1, \"firstName\": \"Alice\", \"lastName\": \"Smith\"}";
            case "v3" -> "{\"userId\": 1, \"fullName\": \"Alice Smith\", \"version\": 3}";
            default -> "{\"error\": \"Unknown API version\"}";
        };
    }
}

public class Main {
    public static void main(String[] args) {
        ApiVersionResolver resolver = new ApiVersionResolver();
        VersionedUserController controller = new VersionedUserController();

        ApiRequest urlVersioned = new ApiRequest("/api/v1/users/1", new HashMap<>(), new HashMap<>());
        ApiRequest headerVersioned = new ApiRequest("/api/users/1",
            Map.of("Accept", "application/vnd.api.v2+json"), new HashMap<>());
        ApiRequest queryVersioned = new ApiRequest("/api/users/1",
            new HashMap<>(), Map.of("version", "3"));

        String v1 = resolver.resolveUrlVersion(urlVersioned);
        String v2 = resolver.resolveHeaderVersion(headerVersioned);
        String v3 = resolver.resolveQueryParamVersion(queryVersioned);

        System.out.println("URL version: " + v1 + " -> " + controller.getUser(v1));
        System.out.println("Header version: " + v2 + " -> " + controller.getUser(v2));
        System.out.println("Query version: " + v3 + " -> " + controller.getUser(v3));
    }
}

